const path = require('path');

const ROOT = '/app';

const clients = [
  { module: 'gbfs-v1', jvmKlass: 'dev/sargunv/mobilitydata/gbfs/v1/GbfsV1Client', klibKlass: 'dev.sargunv.mobilitydata.gbfs.v1/GbfsV1Client' },
  { module: 'gbfs-v2', jvmKlass: 'dev/sargunv/mobilitydata/gbfs/v2/GbfsV2Client', klibKlass: 'dev.sargunv.mobilitydata.gbfs.v2/GbfsV2Client' },
  { module: 'gbfs-v3', jvmKlass: 'dev/sargunv/mobilitydata/gbfs/v3/GbfsV3Client', klibKlass: 'dev.sargunv.mobilitydata.gbfs.v3/GbfsV3Client' },
  { module: 'gofs-v1', jvmKlass: 'dev/sargunv/mobilitydata/gofs/v1/GofsV1Client', klibKlass: 'dev.sargunv.mobilitydata.gofs.v1/GofsV1Client' },
];

function jvmSuffix(name, module) {
  if (module === 'gofs-v1') {
    if (name === 'getWaitTimes') return '-bMdYcbs';
    if (name === 'getRealtimeBookings') return '-tZkwj4A';
  }
  return '-gIAlu-s';
}

function updateJvmApi(module, klass) {
  const file = path.join(ROOT, module, 'api', `${module}.api`);
  let text = fs.readFileSync(file, 'utf8');
  const start = text.indexOf(`public final class ${klass} : java/lang/AutoCloseable {`);
  if (start === -1) throw new Error(`Class not found in ${file}`);
  const end = text.indexOf('\n}', start);
  if (end === -1) throw new Error(`Class end not found in ${file}`);
  let block = text.slice(start, end + 2);
  block = block.replace(/^(\tpublic final fun )(get[A-Za-z]+)( \()/gm, (m, prefix, name, rest) => {
    return `${prefix}${name}${jvmSuffix(name, module)}${rest}`;
  });
  text = text.slice(0, start) + block + text.slice(end + 2);
  fs.writeFileSync(file, text);
}

function updateKlibApi(module, klass) {
  const file = path.join(ROOT, module, 'api', `${module}.klib.api`);
  let text = fs.readFileSync(file, 'utf8');
  const start = text.indexOf(`final class ${klass} : kotlin/AutoCloseable {`);
  if (start === -1) throw new Error(`Class not found in ${file}`);
  const end = text.indexOf('\n}', start);
  if (end === -1) throw new Error(`Class end not found in ${file}`);
  let block = text.slice(start, end + 2);
  block = block.replace(
    /: (dev\.sargunv\.mobilitydata\.(?:gbfs|gofs)\.[a-z0-9]+\/(?:Gbfs|Gofs)FeedResponse<[^>]+>)/g,
    ': kotlin/Result<$1>'
  );
  text = text.slice(0, start) + block + text.slice(end + 2);
  fs.writeFileSync(file, text);
}

for (const { module, jvmKlass, klibKlass } of clients) {
  updateJvmApi(module, jvmKlass);
  updateKlibApi(module, klibKlass);
}

console.log('Updated ABI files.');

